// src/App.js
import React, { useEffect } from "react";
import { useNodesState, useEdgesState } from "reactflow";
import { PipelineToolbar } from "./toolbar";
import { PipelineUI } from "./ui";
import FlowCanvas from "./FlowCanvas";

export default function App() {
  const [nodes, setNodes, onNodesChange] = useNodesState([
    { id: "1", type: "inputNode", position: { x: 50, y: 50 }, data: {} },
    { id: "2", type: "llmNode", position: { x: 300, y: 50 }, data: {} },
    { id: "3", type: "textNode", position: { x: 50, y: 200 }, data: {} },
    { id: "4", type: "outputNode", position: { x: 300, y: 200 }, data: {} },
    {
      id: "5",
      type: "deleteNode",
      position: { x: 550, y: 125 },
      data: { incoming: null, onDelete: () => {} },
    },
  ]);

  const [edges, setEdges, onEdgesChange] = useEdgesState([
    { id: "e1-2", source: "1", target: "2" },
    { id: "e3-2", source: "3", target: "2" },
    { id: "e2-4", source: "2", target: "4" },
  ]);

  // Delete handler: removes target node and the delete node (id "5")
  const handleDeleteNode = (targetId) => {
    console.log("handleDeleteNode called with targetId:", targetId);
    if (!targetId) return;

    setNodes((nds) => nds.filter((n) => n.id !== targetId && n.id !== "5"));
    setEdges((eds) =>
      eds.filter(
        (e) =>
          e.source !== targetId &&
          e.target !== targetId &&
          e.source !== "5" &&
          e.target !== "5"
      )
    );
  };

  // onConnect: add edge and update edges state
  const handleConnect = (params) => {
    const newEdge = {
      id: params.id || `e${params.source}-${params.target}-${Date.now()}`,
      source: params.source,
      target: params.target,
      ...params,
    };
    setEdges((eds) => {
      const next = [...eds, newEdge];
      return next;
    });
  };

  // Keep deleteNode.data.incoming in sync with the canonical edges array
  useEffect(() => {
    // find an edge that targets delete node id "5"
    const incomingEdge = edges.find((e) => e.target === "5");
    const incoming = incomingEdge ? incomingEdge.source : null;

    setNodes((nds) =>
      nds.map((n) =>
        n.id === "5"
          ? { ...n, data: { ...n.data, incoming, onDelete: handleDeleteNode } }
          : n
      )
    );

    // debug
    console.log("edges changed:", edges);
    console.log("deleteNode incoming now:", incoming);
  }, [edges]); // runs whenever edges change

  return (
    <div>
      <PipelineToolbar />
      <PipelineUI />
      <FlowCanvas
        nodes={nodes}
        edges={edges}
        onNodesChange={onNodesChange}
        onEdgesChange={onEdgesChange}
        onConnect={handleConnect}
      />
    </div>
  );
}
